  ('diplomatic-a3078d07-moex-00168', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '依憲法增修條文規定，司法院大法官之人數為幾人？', '["9人", "11人", "15人", "17人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00169', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '依憲法法庭判決及司法院大法官解釋意旨，有關地方自治事項，下列敘述何者錯誤？', '["農田水利灌溉乃專屬地方政府執行之業務事項", "對街頭藝人藝文活動之管制，屬地方自治事項", "電子遊戲場業營業場所之規範，屬工商輔導及管理之事項，係直轄市、縣（市）之自治範圍", "中央依據法律使地方分擔全民健康保險費之補助，尚未侵害地方自治團體財政自主權之核心領域"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00170', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關憲法訴訟法施行前之司法院大法官解釋效力，下列敘述何者錯誤？', '["拘束全國各機關", "拘束全國人民", "依人民聲請所為之解釋，對聲請人據以聲請之案件，具有效力", "如宣告法規範違憲，該法規範自始失其效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00171', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '在美、中二國的兩岸政策上，2021年10月12日，時任美國國防部發言人柯比（JohnKirby）曾經表示： 「美國長期遵循『一中政策』（OneChinaPolicy），這和中共『一中原則』（OneChinaPrinciple）不同。」 有關美國的「一中政策」，下列敘述何者錯誤？', '["1979年的《建交公報》，美、中二國均同意：「世界上只有一個中國，中華人民共和國是中國的唯一 合法政府」", "美、中二國1972年的《上海公報》及1979年的《建交公報》均有提到：「雙方都希望減少國際軍事衝 突的危險」。因此，2022年10月17日，美國國務卿布林肯提到：「美國一中政策不會改變，但其核心 是承諾和平解決分歧。」", "為了避免臺海衝突，美國同意扮演兩岸調停人的角色", "在「一中原則」下，北京宣稱對臺灣擁有主權，但在「一中政策」下，美方對臺灣主權不持立場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00172', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '2022年8月中共國台辦發表了第三份對臺政策「白皮書」：《臺灣問題與新時代中國統一事業》，顯示出 中共對臺政策的一些微妙變化。下列何者並非其中微妙變化之處？', '["第三份白皮書提出的一國兩制方案中，並未提及「臺灣可以有自己的軍隊」", "第三份白皮書重新提出1983年鄧小平的一國兩制方案：「要實現統一，就要有一個適當的方式，所 以我建議舉行兩黨平等會談，實行第三次合作，而不提中央和地方談判。」", "第三份白皮書提出的一國兩制方案中，並未提及中國大陸「不派軍隊也不派行政人員駐臺」", "第三份白皮書中，並未再提及「在一個中國的前提下，什麼問題都可以談」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00173', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '北京雖然至今仍宣示希望能「和平統一」臺灣，但至今依然堅持不承諾放棄使用武力來解決臺灣問題。 北京曾經宣示幾個可能對臺灣使用武力的理由，下列何者並不是其中宣示過的理由？', '["臺灣無限期拖延統一的政治談判", "臺灣內部出現動亂", "臺灣有意義的參與聯合國相關國際組織", "外國勢力介入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00174', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '有關中共「外聯部」的敘述，下列何者錯誤？', '["該部與中共外交部的人事互不流通", "全名是中國共產黨中央委員會對外聯絡部", "是負責「政黨外交」的單位", "與中共外交部相同，屬於「正部級」的位階"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00175', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-113-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '兩岸自1990年代以來，便一直有談判《兩岸軍事互信機制》的呼聲和提議，然而至今一直沒有進展。 下列何者是導致其無法進展的原因？', '["北京堅持兩岸軍事互信之建立上，須先預設「一個中國原則」政治框架前提，這難免會被臺灣人民 視為是北京的政治統戰", "美國反對兩岸軍事互信機制的談判", "北京認為軍事互信機制協議的談判，是屬於國家之間的談判，北京不認為臺灣是一個國家，因此始 終反對和臺灣進行軍事互信機制的談判", "兩岸均認為軍事互信機制的用處不大，因此無意進行談判"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:29+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL)
